'use client'
import Link from 'next/link';
import "../globals.css"; 
import React,{FC, useState, useEffect} from 'react';
import NavItems from '../utils/NavItems';
import {ThemeSwitcher} from "../utils/ThemeSwitcher"
import MobileSidebar from './MobileSidebar';
import { HiOutlineMenuAlt3 } from 'react-icons/hi';


type Props = {
    open?: boolean;
    setOpen?: (open: boolean) => void;
    activeItem: number;
}

// Fixed: Destructured the props so activeItem is defined
const Header:FC<Props> = ({ activeItem, setOpen = () => {}, open = false }) => {
    const [openSidebar, setOpenSidebar] = useState(false);
    const [active, setActive] = useState(false);

    useEffect(() => {
        const handleScroll = () => {
            if (window.scrollY > 80) {
                setActive(true);
            } else {
                setActive(false);
            }
        };

        window.addEventListener("scroll", handleScroll);

        return () => {
            window.removeEventListener("scroll", handleScroll);
        };
    }, []);

  return (
    <div className='w-full relative '>
            <div className={`${
            active 
                        ? "dark:bg-gradient-to-r dark:from-black dark:via-purple-950 dark:to-purple-700 bg-white fixed top-0 left-0 w-full h-20 z-80 border-b dark:border-purple-900 border-gray-200 shadow-xl transition duration-500"
                        : "w-full dark:bg-gradient-to-r dark:from-black dark:via-purple-950 dark:to-purple-700 bg-white border-b dark:border-purple-900 border-gray-200 h-20 z-80 shadow"
            }`}>
                <div className="w-[95%] m-auto py-2 h-full ">
                     <div className="w-full h-20 flex items-center justify-between p-3">
                         <div>
                            <Link href={"/"} 
                            className={`text-[25px] font-Poppins font-medium text-black dark:text-white` } 
                            >
                                ZyLO Learning
                               </Link>
                         </div>
                                                 <div className="flex items-center gap-4">
                                                         {/* Desktop Navigation - Show only on desktop (768px and up) */}
                                                         <div className="hidden md:flex">
                                                                 <NavItems 
                                                                    activeItem={activeItem} 
                                                                    isMobile={false}
                                                                    />
                                                         </div>
                              <ThemeSwitcher/>
                                                            {/* Mobile Menu Icon - Show only on mobile (below 768px) */}
                                                            <div className="md:hidden">
                                 <HiOutlineMenuAlt3
                                    size={25}
                                    className='cursor-pointer dark:text-white text-black'
                                                                        onClick={() => setOpenSidebar(!openSidebar)}
                                     />
                              </div>
                         </div>
                     </div>
                </div>
            </div>
                        {/* Mobile Sidebar */}
                        <MobileSidebar 
                            activeItem={activeItem}
                            open={openSidebar}
                            setOpen={setOpenSidebar}
                        />
    </div>
  );
};

export default Header;